async function seed() {
  console.log(`Seeding ${EXERCISES.length} exercises...`);

  let inserted = 0;
  let skipped = 0;

  for (const ex of EXERCISES) {
    try {
      await db
        .insert(exerciseLibrary)
        .values({
          name: ex.name,
          movementPattern: ex.movementPattern,
          primaryMuscle: ex.primaryMuscle,
          secondaryMuscles: ex.secondaryMuscles,
          equipment: ex.equipment,
          difficultyLevel: ex.difficultyLevel,
          intentTags: ex.intentTags,
          jointStressProfile: ex.jointStressProfile,
          clusterId: ex.clusterId ?? null,
          easierVariations: ex.easierVariations,
          harderVariations: ex.harderVariations,
          description: ex.description,
          isActive: true,
        })
        .onConflictDoNothing();
      inserted++;
    } catch (err: any) {
      console.error(`Failed to insert ${ex.name}:`, err.message);
      skipped++;
    }
  }

  // Summary
  const result = await db.execute(
    sql`SELECT COUNT(*)::int as total, COUNT(DISTINCT cluster_id)::int as clusters FROM exercise_library WHERE is_active = true`
  );
  const stats = result.rows?.[0] ?? result[0] ?? {};
  console.log(`\n✓ Done: ${inserted} inserted, ${skipped} skipped`);
  console.log(`  Library total: ${(stats as any).total} exercises across ${(stats as any).clusters} clusters`);

  process.exit(0);
}

seed().catch((err) => {
  console.error("Seed failed:", err);
  process.exit(1);
});
